// Created: 2026-07-16

/**
 * Tests for posttool/ui-change-detector — the /ork:expect auto-fire nudge.
 *
 * Focus: the per-route cooldown must be scoped per SESSION (#2919). Before
 * the fix the cooldown map was keyed by route alone, so whichever session
 * edited a route second had its nudge silently swallowed by the first
 * session's cooldown.
 */

import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { uiChangeDetector, fileToRoute } from '../../posttool/ui-change-detector.js';

const FIRES_REL = join('.claude', 'state', 'expect-auto-fires.json');

function liveDevStack(tmp: string): void {
  // isDevStackLive() probes tracked PIDs with signal 0 — our own PID is
  // always alive, which makes the stack "live" for the duration of the test.
  mkdirSync(join(tmp, '.claude', 'state'), { recursive: true });
  writeFileSync(
    join(tmp, '.claude', 'state', 'dev-stack.json'),
    JSON.stringify({
      bootedAt: new Date().toISOString(),
      branch: 'test',
      subdomain: 'test',
      baseUrl: 'https://test.localhost',
      processes: { devServer: { pid: process.pid } },
      emulators: [],
    }),
  );
}

function editInput(file: string): never {
  return { tool_name: 'Edit', tool_input: { file_path: file } } as never;
}

describe('ui-change-detector', () => {
  let tmp: string;
  const savedEnv: Record<string, string | undefined> = {};

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'uicd-'));
    for (const k of ['CLAUDE_PROJECT_DIR', 'CLAUDE_SESSION_ID', 'ORK_EXPECT_AUTO']) {
      savedEnv[k] = process.env[k];
    }
    process.env.CLAUDE_PROJECT_DIR = tmp;
    process.env.CLAUDE_SESSION_ID = 'sess-A';
    delete process.env.ORK_EXPECT_AUTO;
    liveDevStack(tmp);
  });

  afterEach(() => {
    for (const [k, v] of Object.entries(savedEnv)) {
      if (v === undefined) delete process.env[k];
      else process.env[k] = v;
    }
    rmSync(tmp, { recursive: true, force: true });
  });

  test('fileToRoute maps app-router pages', () => {
    expect(fileToRoute('app/dashboard/page.tsx')).toBe('/dashboard');
    expect(fileToRoute('pages/api/users.ts')).toBeNull();
  });

  test('fires on a UI edit and records a session-keyed cooldown entry', async () => {
    const r = await uiChangeDetector(editInput('app/dashboard/page.tsx'));
    const ctxText = (r.hookSpecificOutput as { additionalContext?: string })?.additionalContext;
    expect(ctxText).toContain('/ork:expect /dashboard');

    const fires = JSON.parse(readFileSync(join(tmp, FIRES_REL), 'utf8'));
    expect(Object.keys(fires)).toEqual(['sess-A:/dashboard']);
  });

  test('same session within cooldown is silent', async () => {
    await uiChangeDetector(editInput('app/dashboard/page.tsx'));
    const r = await uiChangeDetector(editInput('app/dashboard/page.tsx'));
    expect(r.hookSpecificOutput).toBeUndefined();
  });

  test('a DIFFERENT session still gets its nudge during another session\'s cooldown (#2919)', async () => {
    await uiChangeDetector(editInput('app/dashboard/page.tsx')); // sess-A fires

    process.env.CLAUDE_SESSION_ID = 'sess-B';
    const r = await uiChangeDetector(editInput('app/dashboard/page.tsx'));
    const ctxText = (r.hookSpecificOutput as { additionalContext?: string })?.additionalContext;
    expect(ctxText).toContain('/ork:expect /dashboard');
  });

  test('legacy un-keyed cooldown entries do not suppress and stale entries are pruned (#2919)', async () => {
    // Legacy pre-#2919 shape: bare route key. Old enough to be pruned.
    writeFileSync(
      join(tmp, FIRES_REL),
      JSON.stringify({ '/dashboard': Date.now() - 2 * 3_600_000 }),
    );

    const r = await uiChangeDetector(editInput('app/dashboard/page.tsx'));
    expect((r.hookSpecificOutput as { additionalContext?: string })?.additionalContext).toBeDefined();

    const fires = JSON.parse(readFileSync(join(tmp, FIRES_REL), 'utf8'));
    expect(fires['/dashboard']).toBeUndefined(); // pruned
    expect(fires['sess-A:/dashboard']).toBeTypeOf('number');
  });
});
